var DATA = {
  bps: ["3d-data-terrain-explorer","ab-testing-statistician","accessibility-auditor","activity-feed-designer","adaptive-metric-layout","aesthetic-style-composer","agent-promotion-evaluator","agent-lifecycle-timeline"],
  events: [{bp:"3d-data-terrain-explorer",ts:"23:51",score:90.2,detail:"S:89 J:91 C:90.2",id:4,x:0},{bp:"3d-data-terrain-explorer",ts:"23:57",score:87.2,detail:"S:80 J:92 C:87.2",id:4,x:0.0507},{bp:"3d-data-terrain-explorer",ts:"23:58",score:87.4,detail:"S:91 J:85 C:87.4",id:8,x:0.0623},{bp:"3d-data-terrain-explorer",ts:"00:00",score:86.6,detail:"S:89 J:85 C:86.6",id:12,x:0.0757},{bp:"ab-testing-statistician",ts:"00:01",score:68,detail:"S:62 J:72 C:68.0",id:16,x:0.0883},{bp:"ab-testing-statistician",ts:"00:02",score:73.8,detail:"S:72 J:75 C:73.8",id:20,x:0.1006},{bp:"3d-data-terrain-explorer",ts:"00:03",score:78.4,detail:"S:70 J:84 C:78.4",id:24,x:0.1068},{bp:"3d-data-terrain-explorer",ts:"00:06",score:85.2,detail:"S:84 J:86 C:85.2",id:29,x:0.1372},{bp:"ab-testing-statistician",ts:"00:07",score:92.2,detail:"S:94 J:91.0 C:92.2",id:32,x:0.1409},{bp:"3d-data-terrain-explorer",ts:"00:08",score:90.4,detail:"S:91 J:90 C:90.4",id:35,x:0.1555},{bp:"3d-data-terrain-explorer",ts:"00:12",score:93,detail:"S:87 J:97 C:93.0",id:39,x:0.191},{bp:"3d-data-terrain-explorer",ts:"00:42",score:91,detail:"S:88.0 J:93 C:91.0",id:44,x:0.4709},{bp:"3d-data-terrain-explorer",ts:"00:45",score:68,detail:"S:62 J:72 C:68.0",id:48,x:0.4955},{bp:"accessibility-auditor",ts:"00:46",score:51,detail:"S:30 J:65 C:51.0",id:5,x:0.5088},{bp:"activity-feed-designer",ts:"00:47",score:84.6,detail:"S:72 J:93.0 C:84.6",id:7,x:0.5117},{bp:"activity-feed-designer",ts:"00:48",score:92.6,detail:"S:92 J:93 C:92.6",id:12,x:0.5257},{bp:"activity-feed-designer",ts:"00:51",score:92.2,detail:"S:91 J:93 C:92.2",id:16,x:0.5487},{bp:"accessibility-auditor",ts:"00:52",score:88,detail:"S:82 J:92 C:88.0",id:20,x:0.5587},{bp:"activity-feed-designer",ts:"00:53",score:91,detail:"S:88 J:93 C:91.0",id:23,x:0.5661},{bp:"activity-feed-designer",ts:"00:54",score:88.6,detail:"S:82 J:93 C:88.6",id:27,x:0.5803},{bp:"activity-feed-designer",ts:"00:56",score:94.6,detail:"S:91 J:97 C:94.6",id:31,x:0.5957},{bp:"activity-feed-designer",ts:"00:58",score:89.4,detail:"S:93 J:87 C:89.4",id:35,x:0.6167},{bp:"activity-feed-designer",ts:"01:00",score:88.2,detail:"S:90 J:87 C:88.2",id:39,x:0.6333},{bp:"activity-feed-designer",ts:"01:05",score:69.2,detail:"S:68 J:70 C:69.2",id:43,x:0.6777},{bp:"adaptive-metric-layout",ts:"01:07",score:87.2,detail:"S:83 J:90 C:87.2",id:4,x:0.6974},{bp:"aesthetic-style-composer",ts:"01:08",score:86.8,detail:"S:79 J:92 C:86.8",id:8,x:0.7048},{bp:"adaptive-metric-layout",ts:"01:09",score:80.2,detail:"S:76 J:83 C:80.2",id:12,x:0.7182},{bp:"adaptive-metric-layout",ts:"01:12",score:77,detail:"S:56 J:91 C:77.0",id:16,x:0.7445},{bp:"aesthetic-style-composer",ts:"01:13",score:85.4,detail:"S:80 J:89 C:85.4",id:21,x:0.7554},{bp:"adaptive-metric-layout",ts:"01:14",score:89.8,detail:"S:82 J:95 C:89.8",id:24,x:0.76},{bp:"adaptive-metric-layout",ts:"01:16",score:77.2,detail:"S:58 J:90 C:77.2",id:29,x:0.7794},{bp:"aesthetic-style-composer",ts:"01:16",score:83.8,detail:"S:82 J:85 C:83.8",id:32,x:0.7844},{bp:"aesthetic-style-composer",ts:"01:19",score:85.2,detail:"S:78 J:90 C:85.2",id:36,x:0.813},{bp:"adaptive-metric-layout",ts:"01:21",score:88.2,detail:"S:84 J:91 C:88.2",id:40,x:0.8306},{bp:"aesthetic-style-composer",ts:"01:23",score:75.6,detail:"S:72 J:78 C:75.6",id:44,x:0.8471},{bp:"adaptive-metric-layout",ts:"01:25",score:62,detail:"S:62 J:62 C:62.0",id:48,x:0.8679},{bp:"aesthetic-style-composer",ts:"01:26",score:63.2,detail:"S:65 J:62 C:63.2",id:51,x:0.8753},{bp:"agent-promotion-evaluator",ts:"01:28",score:90.2,detail:"S:86 J:93 C:90.2",id:4,x:0.8977},{bp:"agent-lifecycle-timeline",ts:"01:36",score:75.6,detail:"S:78 J:74 C:75.6",id:8,x:0.9655},{bp:"agent-promotion-evaluator",ts:"01:38",score:44.8,detail:"S:25 J:58 C:44.8",id:12,x:0.9884},{bp:"agent-lifecycle-timeline",ts:"01:39",score:83,detail:"S:77 J:87 C:83.0",id:16,x:0.9997},{bp:"agent-lifecycle-timeline",ts:"01:40",score:83,detail:"S:77 J:87 C:83.0",id:15,x:1}]
};

var MARGIN = {top: 60, right: 40, bottom: 100, left: 200};
var W = 1200, H = 650;
var TRACK_H = 50;
var TRACK_GAP = 8;
var NODE_R = 10;

var timelineW = W - MARGIN.left - MARGIN.right;
var timelineTop = MARGIN.top;
var timelineBot = H - MARGIN.bottom - 40;

var svg = document.querySelector('svg');
var ns = 'http://www.w3.org/2000/svg';

function createElem(tag, attrs, parent) {
  var el = document.createElementNS(ns, tag);
  for (var k in attrs) el.setAttribute(k, attrs[k]);
  if (parent) parent.appendChild(el);
  return el;
}

// Track labels
DATA.bps.forEach(function(bp, i) {
  var y = timelineTop + i * (TRACK_H + TRACK_GAP);
  // Horizontal line
  createElem('line', {
    x1: MARGIN.left, y1: y + TRACK_H/2,
    x2: MARGIN.left + timelineW, y2: y + TRACK_H/2,
    stroke: '#2a2a4a', 'stroke-width': 1
  }, svg);
  // Label
  var label = createElem('text', {
    x: MARGIN.left - 10, y: y + TRACK_H/2 + 4,
    'text-anchor': 'end', fill: '#a0a0c0', 'font-size': '12',
    'font-family': 'monospace'
  }, svg);
  label.textContent = bp;
});

// Time axis ticks
var tickCount = 12;
for (var t = 0; t <= tickCount; t++) {
  var x = MARGIN.left + (t / tickCount) * timelineW;
  var label = createElem('text', {
    x: x, y: timelineTop + DATA.bps.length * (TRACK_H + TRACK_GAP) + 15,
    'text-anchor': 'middle', fill: '#606080', 'font-size': '10'
  }, svg);
  var hrs = Math.floor(t / tickCount * 108.1);
  var mins = Math.round((t / tickCount * 108.1 - hrs) * 60);
  label.textContent = (23 + Math.floor((hrs+8)/60)) % 24 + ':' + String((mins + 8 + (hrs%60)*60) % 60).padStart(2,'0');
}

// Legend
var legendY = H - 70;
createElem('circle', {cx: MARGIN.left + 10, cy: legendY, r: 6, fill: 'url(#goldNode)'}, svg);
createElem('text', {x: MARGIN.left + 22, y: legendY + 4, fill: '#808080', 'font-size': '11'}, svg).textContent = 'Production (85+)';
createElem('circle', {cx: MARGIN.left + 170, cy: legendY, r: 6, fill: 'url(#amberNode)'}, svg);
createElem('text', {x: MARGIN.left + 182, y: legendY + 4, fill: '#808080', 'font-size': '11'}, svg).textContent = 'Refinery (70-84)';
createElem('circle', {cx: MARGIN.left + 340, cy: legendY, r: 6, fill: 'url(#coolNode)'}, svg);
createElem('text', {x: MARGIN.left + 352, y: legendY + 4, fill: '#808080', 'font-size': '11'}, svg).textContent = 'Below gate (<70)';

// Controls
var sliderX = MARGIN.left + 530;
var sliderW = 300;
createElem('text', {x: sliderX, y: legendY, fill: '#808080', 'font-size': '11', 'text-anchor': 'end'}, svg).textContent = 'Scrub:';
var slider = createElem('input', {
  type: 'range', min: '0', max: '1', step: '0.001', value: '1',
  style: 'position:absolute;left:' + (sliderX+10) + 'px;top:' + (legendY-12) + 'px;width:' + sliderW + 'px;accent-color:#ffd700'
}, svg.parentElement);

var playBtn = createElem('button', {
  style: 'position:absolute;left:' + (sliderX+sliderW+20) + 'px;top:' + (legendY-14) + 'px;background:#2a2a4a;color:#e0e0e0;border:1px solid #4a4a6a;border-radius:4px;padding:2px 12px;cursor:pointer;font-size:11px'
}, svg.parentElement);
playBtn.textContent = 'PLAY';

// Popup
var popup = createElem('div', {
  style: 'position:absolute;display:none;background:#1a1a3a;border:1px solid #4a4a6a;border-radius:6px;padding:10px 14px;font-size:12px;color:#e0e0e0;box-shadow:0 4px 20px rgba(0,0,0,0.6);pointer-events:none;z-index:10;max-width:300px'
}, svg.parentElement);

// Track current showing event index for popup
var currentEventIdx = -1;

function getScoreColor(score) {
  if (score >= 85) return 'url(#goldNode)';
  if (score >= 70) return 'url(#amberNode)';
  return 'url(#coolNode)';
}

function getScoreGlow(score) {
  if (score >= 85) return 'url(#glowGold)';
  if (score >= 70) return 'url(#glowAmber)';
  return 'none';
}

// Render all nodes initially (hidden by scrubber)
var allNodes = [];
DATA.events.forEach(function(e, idx) {
  var bi = DATA.bps.indexOf(e.bp);
  if (bi < 0) return;
  var y = timelineTop + bi * (TRACK_H + TRACK_GAP) + TRACK_H/2;
  var x = MARGIN.left + e.x * timelineW;
  var color = getScoreColor(e.score);
  var glow = getScoreGlow(e.score);
  var g = createElem('g', {filter: glow}, svg);
  var node = createElem('circle', {
    cx: x, cy: y, r: NODE_R, fill: color, stroke: '#0d0d1a', 'stroke-width': 1.5,
    cursor: 'pointer', opacity: '0', 'data-idx': idx,
    class: 'timeline-node'
  }, g);
  var label = createElem('text', {
    x: x, y: y - NODE_R - 8, 'text-anchor': 'middle', fill: '#e0e0e0',
    'font-size': '9', 'font-weight': 'bold', opacity: '0', 'data-idx': idx,
    class: 'timeline-label'
  }, svg);
  label.textContent = e.score;
  allNodes.push({node: node, label: label, x: x, y: y, e: e, idx: idx});
});

// Mouse events for nodes
allNodes.forEach(function(n) {
  n.node.addEventListener('click', function(evt) {
    var idx = parseInt(this.getAttribute('data-idx'));
    showPopup(idx, evt.clientX, evt.clientY);
  });
  n.node.addEventListener('mouseenter', function(evt) {
    var idx = parseInt(this.getAttribute('data-idx'));
    showPopup(idx, evt.clientX, evt.clientY);
    this.setAttribute('r', NODE_R + 3);
  });
  n.node.addEventListener('mouseleave', function() {
    hidePopup();
    this.setAttribute('r', NODE_R);
  });
});

function showPopup(idx, cx, cy) {
  var e = DATA.events[idx];
  popup.innerHTML = '<b>' + e.bp + '</b> @ ' + e.ts +
    '<br>score: <b>' + e.score + '</b>' +
    '<br>detail: ' + e.detail +
    '<br>run_id: ' + e.id;
  var px = Math.min(cx - 10, W - 310);
  var py = Math.min(cy - 80, H - 160);
  if (px < 10) px = 10;
  if (py < 10) py = 10;
  popup.style.left = px + 'px';
  popup.style.top = py + 'px';
  popup.style.display = 'block';
  currentEventIdx = idx;
}

function hidePopup() {
  popup.style.display = 'none';
  currentEventIdx = -1;
}

// Scrubber logic
var playing = false;
var playInterval = null;

function updateTimeline(frac) {
  allNodes.forEach(function(n) {
    var show = n.e.x <= frac;
    n.node.setAttribute('opacity', show ? 1 : 0);
    n.label.setAttribute('opacity', show ? 1 : 0);
  });
}

slider.addEventListener('input', function() {
  var frac = parseFloat(this.value);
  updateTimeline(frac);
});

playBtn.addEventListener('click', function() {
  playing = !playing;
  playBtn.textContent = playing ? 'PAUSE' : 'PLAY';
  if (playing) {
    slider.value = '0';
    updateTimeline(0);
    playInterval = setInterval(function() {
      var val = parseFloat(slider.value);
      if (val >= 1) {
        clearInterval(playInterval);
        playing = false;
        playBtn.textContent = 'REPLAY';
        return;
      }
      val += 0.003;
      if (val > 1) val = 1;
      slider.value = val;
      updateTimeline(val);
    }, 150);
  } else {
    if (playInterval) {
      clearInterval(playInterval);
      playInterval = null;
    }
  }
});

// Initial render: show all
updateTimeline(1);
slider.value = '1';
